  validateEmail: (email) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  },

  validatePassword: (password) => {
    // Min 8 chars, at least one uppercase, one lowercase, one number
    const passwordRegex = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d).{8,}$/;
    return passwordRegex.test(password);
  },

  validateRegistration: (data) => {
    const errors = {};

    if (!data.email || !validator.validateEmail(data.email)) {
      errors.email = 'Valid email is required';
    }

    if (!data.password || !validator.validatePassword(data.password)) {
      errors.password = 'Password must be at least 8 characters with uppercase, lowercase, and number';
    }

    if (data.daily_calorie_target && (data.daily_calorie_target < 500 || data.daily_calorie_target > 10000)) {
      errors.daily_calorie_target = 'Daily calorie target must be between 500 and 10000';
    }

    return Object.keys(errors).length === 0 ? null : errors;
  },

  validateFoodLog: (data) => {
    const errors = {};

    if (!data.food_id || typeof data.food_id !== 'number') {
      errors.food_id = 'Valid food_id is required';
    }

    if (!data.log_date || isNaN(new Date(data.log_date))) {
