const USDA_API_KEY = process.env.USDA_API_KEY;
const USDA_BASE_URL = 'https://fdc.nal.usda.gov/api/foods';
const CACHE_TTL = 30 * 24 * 60 * 60 * 1000; // 30 days
const RATE_LIMIT_DELAY = 100; // ms between requests

class FoodService {
  constructor() {
    this.lastRequestTime = 0;
  }

  /**
   * Search foods by name
   * @param {string} query - Search query
   * @param {object} options - Search options (pageSize, pageNumber)
   * @returns {Promise<object>} - Search results with pagination
   */
  async searchFoods(query, options = {}) {
    const { pageSize = 10, pageNumber = 1 } = options;

    if (!query || query.trim().length < 2) {
      throw new ApiError('Search query must be at least 2 characters', 400);
    }

    const trimmedQuery = query.trim();
    const skip = (pageNumber - 1) * pageSize;

    try {
      // Try local cache first
      const cachedFoods = await Food.find(
        { $text: { $search: trimmedQuery } },
        { score: { $meta: 'textScore' } }
      )
        .sort({ score: { $meta: 'textScore' } })
        .limit(pageSize)
        .skip(skip)
        .lean();

      if (cachedFoods.length > 0) {
        const total = await Food.countDocuments({
          $text: { $search: trimmedQuery }
        });
        return {
          foods: this.normalizeFood(cachedFoods),
          total,
          pageNumber,
          pageSize,
          source: 'cache'
        };
      }

      // Fall back to USDA API
      const results = await this.searchUSDAFoods(trimmedQuery, pageSize);

      // Cache results asynchronously
      results.foods.forEach(food => this.cacheFoodAsync(food));

      return {
        ...results,
        pageNumber,
        pageSize,
        source: 'usda'
      };
    } catch (error) {
      logger.error('Food search error', { query, error: error.message });
      throw new ApiError('Food search failed. Please try again.', 500);
    }
  }

  /**
   * Get detailed nutrition for a specific food
   * @param {string} foodId - Food ID (USDA FDC ID or MongoDB ID)
   * @returns {Promise<object>} - Detailed food information
   */
  async getFoodDetails(foodId) {
    try {
      // Try local database first
      let food = await Food.findOne({
        $or: [{ fdcId: foodId }, { _id: foodId }]
      }).lean();

      if (food) {
        return this.normalizeFood([food])[0];
      }

      // Fetch from USDA API
      food = await this.fetchUSDAFood(foodId);
      await this.cacheFoodAsync(food);

      return food;
    } catch (error) {
      logger.error('Get food details error', { foodId, error: error.message });
      throw new ApiError('Food not found', 404);
    }
  }

